cd /tmp/sv-77014ed062144fadba5aba7d0db2df62/simple-solution && dotnet list package --format json 2>/dev/null | python3 -c "import sys,json; data=json.load(sys.stdin); json.dump(data,open('after-cpm-packages.json','w'),indent=2)" && python3 -c "
import json
b = json.load(open('baseline-packages.json'))
a = json.load(open('after-cpm-packages.json'))
def extract(d):
    pkgs = {}
    for p in d['projects']:
        name = p['path'].split('/')[-2]
        for fw in p['frameworks']:
            for pkg in fw.get('topLevelPackages', []):
                pkgs.setdefault(name, {})[pkg['id']] = pkg['resolvedVersion']
    return pkgs
bp, ap = extract(b), extract(a)
match = bp == ap
print('Package versions match baseline:', match)
if not match:
    for proj in set(list(bp.keys()) + list(ap.keys())):
        for pkg in set(list(bp.get(proj,{}).keys()) + list(ap.get(proj,{}).keys())):
            bv = bp.get(proj,{}).get(pkg,'MISSING')
            av = ap.get(proj,{}).get(pkg,'MISSING')
            if bv != av:
                print(f'  {proj}/{pkg}: {bv} -> {av}')
"

